import { klona } from 'klona';
import _ from 'lodash';
import { computed, reactive, ref } from 'vue';
import { defineStore } from 'pinia';

import { applyConnectionSnapshot, captureCurrentConnectionSnapshot } from '../core/connectionSticky';
import { mutateAssistantState, readAssistantState, writeAssistantState } from '../core/persistence';
import {
  buildPromptKey,
  clonePreset,
  cloneSettings,
  createDefaultPrompt,
  getPromptKind,
  normalizeTags,
} from '../core/presetMapper';
import type {
  AutoSaveTask,
  BrowseParamDraftState,
  BrowsePromptListState,
  EditApplyMode,
  PendingAction,
  PresetSummary,
  PromptQuickItem,
  QuickPromptToggleState,
  UiMode,
  UnsavedDecision,
} from '../types';

type ReplacePresetRender = 'debounced' | 'immediate' | 'none';

interface PresetPreviewInfo {
  prompt_count: number;
  enabled_prompt_count: number;
}

const SAVE_FEEDBACK_MS = 1200;
const EDIT_LIVE_APPLY_DELAY_MS = 260;

function createInitialSettings(): Preset['settings'] {
  const globalDefault = (globalThis as { default_preset?: Preset }).default_preset;
  if (globalDefault?.settings) {
    return cloneSettings(globalDefault.settings);
  }
  try {
    const inUsePreset = getPreset('in_use');
    if (inUsePreset?.settings) {
      return cloneSettings(inUsePreset.settings);
    }
  } catch (error) {
    console.warn('[PresetAssistant] failed to read in_use preset settings:', error);
  }
  return {} as Preset['settings'];
}

function normalizePromptEntry(prompt: PresetPrompt, fallbackIndex: number): PresetPrompt {
  const next = { ...prompt };
  const fallbackId = `prompt_${fallbackIndex + 1}`;
  if (typeof next.id !== 'string' || !next.id.trim()) {
    next.id = fallbackId;
  }
  if (typeof next.name !== 'string' || !next.name.trim()) {
    next.name = next.id;
  }
  if (typeof next.enabled !== 'boolean') {
    next.enabled = true;
  }
  if (next.role !== 'system' && next.role !== 'user' && next.role !== 'assistant') {
    next.role = 'system';
  }
  return next as PresetPrompt;
}

function getBuiltinPromptManager(): Record<string, unknown> | null {
  const root = globalThis as Record<string, unknown>;
  const contexts: Array<Record<string, unknown> | null> = [root];
  for (const accessor of ['parent', 'top', 'window'] as const) {
    try {
      const context = root[accessor] as Record<string, unknown> | null | undefined;
      if (context && typeof context === 'object') {
        contexts.push(context);
      }
    } catch {
      // Cross-origin frame access can throw; ignore and continue.
    }
  }

  function pickPromptManagerFromContext(context: Record<string, unknown>): Record<string, unknown> | null {
    const directBuiltin = context.builtin as Record<string, unknown> | undefined;
    if (directBuiltin && typeof directBuiltin === 'object') {
      const directPromptManager = directBuiltin.promptManager as Record<string, unknown> | undefined;
      if (directPromptManager && typeof directPromptManager === 'object') {
        return directPromptManager;
      }
    }

    const helper = context.TavernHelper as Record<string, unknown> | undefined;
    if (helper && typeof helper === 'object') {
      const helperBuiltin = helper.builtin as Record<string, unknown> | undefined;
      if (helperBuiltin && typeof helperBuiltin === 'object') {
        const helperPromptManager = helperBuiltin.promptManager as Record<string, unknown> | undefined;
        if (helperPromptManager && typeof helperPromptManager === 'object') {
          return helperPromptManager;
        }
      }
    }

    return null;
  }

  for (const context of contexts) {
    if (!context || typeof context !== 'object') {
      continue;
    }
    try {
      const promptManager = pickPromptManagerFromContext(context);
      if (promptManager) {
        return promptManager;
      }
    } catch {
      // Ignore invalid contexts and continue searching.
    }
  }
  return null;
}

function toPromptCollection(raw: unknown): unknown[] {
  if (Array.isArray(raw)) {
    return raw;
  }
  if (!raw || typeof raw !== 'object') {
    return [];
  }
  const record = raw as Record<string, unknown>;
  if (Array.isArray(record.collection)) {
    return record.collection;
  }
  if (Array.isArray(record.prompts)) {
    return record.prompts;
  }
  return [];
}

function toPromptArray(raw: unknown): unknown[] {
  if (Array.isArray(raw)) {
    return raw;
  }
  if (!raw || typeof raw !== 'object') {
    return [];
  }
  return Object.values(raw as Record<string, unknown>).filter(value => value && typeof value === 'object');
}

function toPromptRole(raw: unknown): PresetPrompt['role'] {
  return raw === 'assistant' || raw === 'user' ? raw : 'system';
}

function toPromptPosition(raw: Record<string, unknown>): PresetPrompt['position'] {
  const rawPosition = raw.position;
  if (rawPosition && typeof rawPosition === 'object') {
    const position = rawPosition as Record<string, unknown>;
    if (position.type === 'in_chat') {
      return {
        type: 'in_chat',
        depth: Number.isFinite(position.depth)
          ? Math.max(0, Number(position.depth))
          : Number.isFinite(raw.injection_depth)
            ? Math.max(0, Number(raw.injection_depth))
            : 4,
        order: Number.isFinite(position.order)
          ? Number(position.order)
          : Number.isFinite(raw.injection_order)
            ? Number(raw.injection_order)
            : 100,
      };
    }
    if (position.type === 'relative') {
      return { type: 'relative' };
    }
  }

  const explicitType = raw.position_type;
  if (explicitType === 'in_chat') {
    return {
      type: 'in_chat',
      depth: Number.isFinite(raw.injection_depth) ? Math.max(0, Number(raw.injection_depth)) : 4,
      order: Number.isFinite(raw.injection_order) ? Number(raw.injection_order) : 100,
    };
  }

  const injectionPosition = Number(raw.injection_position);
  if (Number.isFinite(injectionPosition) && injectionPosition === 1) {
    return {
      type: 'in_chat',
      depth: Number.isFinite(raw.injection_depth) ? Math.max(0, Number(raw.injection_depth)) : 4,
      order: Number.isFinite(raw.injection_order) ? Number(raw.injection_order) : 100,
    };
  }

  return { type: 'relative' };
}

function coercePromptFromUnknown(rawPrompt: unknown, index: number): PresetPrompt | null {
  if (!rawPrompt || typeof rawPrompt !== 'object') {
    return null;
  }
  const raw = rawPrompt as Record<string, unknown>;
  const idCandidate = [raw.identifier, raw.id, raw.key, raw.name].find(value => typeof value === 'string');
  const nameCandidate = [raw.name, raw.title, raw.identifier, raw.id].find(value => typeof value === 'string');
  const roleCandidate = [raw.role, raw.injection_role].find(value => typeof value === 'string');
  const contentCandidate = [raw.content, raw.prompt, raw.text, raw.value].find(value => typeof value === 'string');
  const enabledCandidate = raw.enabled;
  const disabledCandidate = raw.disabled;

  const id = typeof idCandidate === 'string' && idCandidate.trim() ? idCandidate : `pm_${index + 1}`;
  const name = typeof nameCandidate === 'string' && nameCandidate.trim() ? nameCandidate : id;
  const enabled =
    typeof enabledCandidate === 'boolean'
      ? enabledCandidate
      : typeof disabledCandidate === 'boolean'
        ? !disabledCandidate
        : true;
  const prompt: PresetPrompt = {
    id,
    name,
    enabled,
    role: toPromptRole(roleCandidate),
    position: toPromptPosition(raw),
    content: typeof contentCandidate === 'string' ? contentCandidate : '',
  };
  return normalizePromptEntry(prompt, index);
}

function dedupePrompts(prompts: PresetPrompt[]): PresetPrompt[] {
  const seen = new Set<string>();
  const unique: PresetPrompt[] = [];
  for (const prompt of prompts) {
    const key = `${prompt.id}::${prompt.role}::${prompt.name}`;
    if (seen.has(key)) {
      continue;
    }
    seen.add(key);
    unique.push(prompt);
  }
  return unique;
}

function extractPromptsFromPresetSource(source: unknown): PresetPrompt[] {
  if (!source || typeof source !== 'object') {
    return [];
  }
  const raw = source as Record<string, unknown>;
  const rawPrompts = toPromptArray(raw.prompts);
  const rawUnused = toPromptArray(raw.prompts_unused);
  const merged = dedupePrompts(
    [...rawPrompts, ...rawUnused]
      .map((item, index) => coercePromptFromUnknown(item, index))
      .filter((item): item is PresetPrompt => Boolean(item)),
  );
  const rawPromptOrder = Array.isArray(raw.prompt_order) ? raw.prompt_order : [];
  const orderContainer = rawPromptOrder.find(
    item => item && typeof item === 'object' && Array.isArray((item as Record<string, unknown>).order),
  ) as Record<string, unknown> | undefined;
  const rawOrder = orderContainer && Array.isArray(orderContainer.order) ? orderContainer.order : [];
  if (merged.length < 1 && rawOrder.length > 0) {
    return dedupePrompts(
      rawOrder
        .map((entry, index) => {
          if (!entry || typeof entry !== 'object') {
            return null;
          }
          const item = entry as Record<string, unknown>;
          const identifier = typeof item.identifier === 'string' && item.identifier.trim() ? item.identifier : '';
          if (!identifier) {
            return null;
          }
          const prompt: PresetPrompt = {
            id: identifier,
            name: identifier,
            enabled: typeof item.enabled === 'boolean' ? item.enabled : true,
            role: 'system',
            position: { type: 'relative' },
            content: '',
          };
          return normalizePromptEntry(prompt, index);
        })
        .filter((item): item is PresetPrompt => Boolean(item)),
    );
  }

  if (merged.length < 1) {
    return [];
  }

  if (rawOrder.length < 1) {
    return merged;
  }

  const promptsById = new Map<string, PresetPrompt[]>();
  for (const prompt of merged) {
    const queue = promptsById.get(prompt.id) ?? [];
    queue.push(prompt);
    promptsById.set(prompt.id, queue);
  }

  const consumed = new Set<PresetPrompt>();
  const ordered: PresetPrompt[] = [];
  for (const entry of rawOrder) {
    if (!entry || typeof entry !== 'object') {
      continue;
    }
    const orderItem = entry as Record<string, unknown>;
    const identifier = typeof orderItem.identifier === 'string' ? orderItem.identifier : '';
    if (!identifier) {
      continue;
    }
    const queue = promptsById.get(identifier);
    const prompt = queue?.shift();
    if (!prompt) {
      continue;
    }
    consumed.add(prompt);
    const enabled = typeof orderItem.enabled === 'boolean' ? orderItem.enabled : prompt.enabled;
    ordered.push(
      normalizePromptEntry(
        {
          ...prompt,
          enabled,
        },
        ordered.length,
      ),
    );
  }

  if (ordered.length < 1) {
    return merged;
  }
  const rest = merged.filter(prompt => !consumed.has(prompt));
  return dedupePrompts([...ordered, ...rest]);
}

function getPromptsFromPromptManagerCollection(): PresetPrompt[] {
  try {
    const promptManager = getBuiltinPromptManager();
    if (!promptManager) {
      return [];
    }
    const getter = promptManager.getPromptCollection;
    const fromGetter = toPromptCollection(typeof getter === 'function' ? getter.call(promptManager) : null);
    const directCollection = toPromptCollection(promptManager.collection);
    const directPrompts = toPromptCollection(promptManager.prompts);
    const promptCollection = toPromptCollection(promptManager.promptCollection);
    const mergedRaw = [...fromGetter, ...directCollection, ...directPrompts, ...promptCollection];
    if (mergedRaw.length < 1) {
      return [];
    }
    const prompts = mergedRaw
      .map((item, index) => coercePromptFromUnknown(item, index))
      .filter((item): item is PresetPrompt => Boolean(item));
    return dedupePrompts(prompts);
  } catch (error) {
    console.warn('[PresetAssistant] prompt manager collection unavailable:', error);
    return [];
  }
}

function getPromptsFromPromptManagerMessages(): PresetPrompt[] {
  try {
    const promptManager = getBuiltinPromptManager();
    if (!promptManager) {
      return [];
    }
    const messagesRaw = promptManager.messages;
    if (!Array.isArray(messagesRaw) || messagesRaw.length < 1) {
      return [];
    }
    const latestWithCollection = [...messagesRaw]
      .reverse()
      .find(item => item && typeof item === 'object' && Array.isArray((item as Record<string, unknown>).collection));
    if (!latestWithCollection || typeof latestWithCollection !== 'object') {
      return [];
    }
    const collection = toPromptCollection((latestWithCollection as Record<string, unknown>).collection);
    if (collection.length < 1) {
      return [];
    }
    const prompts = collection
      .map((item, index) => coercePromptFromUnknown(item, index))
      .filter((item): item is PresetPrompt => Boolean(item));
    return dedupePrompts(prompts);
  } catch (error) {
    console.warn('[PresetAssistant] prompt manager messages unavailable:', error);
    return [];
  }
}

function getFallbackPromptsFromHost(): PresetPrompt[] {
  const promptManagerPrompts = getPromptsFromPromptManagerCollection();
  if (promptManagerPrompts.length > 0) {
    return promptManagerPrompts;
  }
  const messagePrompts = getPromptsFromPromptManagerMessages();
  if (messagePrompts.length > 0) {
    return messagePrompts;
  }
  try {
    const inUse = getPreset('in_use');
    const promptsFromInUse = extractPromptsFromPresetSource(inUse);
    if (promptsFromInUse.length > 0) {
      return promptsFromInUse;
    }
  } catch (error) {
    console.warn('[PresetAssistant] fallback in_use prompts unavailable:', error);
  }
  const globalDefault = (globalThis as { default_preset?: Preset }).default_preset;
  if (globalDefault) {
    const promptsFromDefault = extractPromptsFromPresetSource(globalDefault);
    if (promptsFromDefault.length > 0) {
      return promptsFromDefault;
    }
  }
  return [];
}

function normalizePresetForAssistant(preset: Preset, fallbackPrompts: PresetPrompt[] = []): Preset {
  const next = clonePreset(preset);
  const normalizedPrompts = extractPromptsFromPresetSource(next);
  if (normalizedPrompts.length > 0) {
    next.prompts = normalizedPrompts;
    return next;
  }

  if (fallbackPrompts.length > 0) {
    next.prompts = fallbackPrompts.map((prompt, index) => normalizePromptEntry(prompt, index));
    return next;
  }

  next.prompts = [];
  return next;
}

export const usePresetAssistantStore = defineStore('preset-assistant', () => {
  const assistantState = ref(readAssistantState());
  const initialSettings = createInitialSettings();

  const presetNames = ref<string[]>([]);
  const presetPreviewMap = ref<Record<string, PresetPreviewInfo>>({});
  const selectedPresetName = ref('');
  const selectedPreset = ref<Preset | null>(null);
  const loadedPresetName = ref('');
  const loadingPreset = ref(false);
  const initialized = ref(false);

  const editDraft = ref<Preset | null>(null);
  const editDraftDirty = ref(false);
  const editSelectedPromptIndex = ref(0);
  const editPromptQuery = ref('');
  const editSaving = ref(false);
  let editLiveApplyTimer: number | null = null;

  const unsavedDialogVisible = ref(false);
  const unsavedDialogReason = ref('');
  const pendingAction = ref<PendingAction | null>(null);

  const quickPromptToggleState = reactive<QuickPromptToggleState>({
    saving_ids: new Set<string>(),
    last_saved_at_by_id: {},
  });

  const browseListState = reactive<BrowsePromptListState>({
    query: '',
    selection: { indices: new Set<number>() },
    saving: false,
    last_saved_at: 0,
    dragging: false,
  });

  const browseParamDraft = reactive<BrowseParamDraftState>({
    base_settings: cloneSettings(initialSettings),
    staged_settings: cloneSettings(initialSettings),
    dirty: false,
    applying: false,
  });

  const subscriptions = ref<EventOnReturn[]>([]);
  let browseAutoSaveChain: Promise<void> = Promise.resolve();
  let browseAutoSaveRunning = 0;
  let browseAutoSaveCounter = 0;

  const uiMode = computed({
    get: () => assistantState.value.ui.mode,
    set: value => {
      mutateState(draft => {
        draft.ui.mode = value;
      });
    },
  });

  const apiBindingMode = computed({
    get: () => assistantState.value.ui.api_binding_mode,
    set: value => {
      mutateState(draft => {
        draft.ui.api_binding_mode = value;
      });
      if (value === 'sticky_connection') {
        void refreshStickyConnectionSnapshot();
      }
    },
  });

  const editApplyMode = computed({
    get: () => assistantState.value.ui.edit_apply_mode,
    set: value => {
      mutateState(draft => {
        draft.ui.edit_apply_mode = value;
      });
    },
  });

  const browseParamPanelOpen = computed({
    get: () => assistantState.value.ui.browse_param_panel_open,
    set: value => {
      mutateState(draft => {
        draft.ui.browse_param_panel_open = value;
      });
    },
  });

  const browseParamExpandedGroup = computed({
    get: () => assistantState.value.ui.browse_param_last_expanded_group,
    set: value => {
      mutateState(draft => {
        draft.ui.browse_param_last_expanded_group = value;
      });
    },
  });

  const hasUnsavedChanges = computed(() => browseParamDraft.dirty || editDraftDirty.value);

  const selectedMeta = computed(() => ensureMeta(selectedPresetName.value));

  const quickPromptItems = computed<PromptQuickItem[]>(() => {
    if (!selectedPreset.value) {
      return [];
    }
    return selectedPreset.value.prompts.map((prompt, index) => {
      const key = buildPromptKey(prompt, index);
      return {
        index,
        key,
        id: prompt.id,
        name: prompt.name,
        role: prompt.role,
        enabled: prompt.enabled,
        kind: getPromptKind(prompt),
        selected: browseListState.selection.indices.has(index),
        is_saving: quickPromptToggleState.saving_ids.has(key),
        is_recently_saved: _.isNumber(quickPromptToggleState.last_saved_at_by_id[key]),
      };
    });
  });

  const filteredBrowsePromptItems = computed<PromptQuickItem[]>(() => {
    const keyword = browseListState.query.trim().toLowerCase();
    if (!keyword) {
      return quickPromptItems.value;
    }
    return quickPromptItems.value.filter(item => {
      return (
        item.name.toLowerCase().includes(keyword) ||
        item.id.toLowerCase().includes(keyword) ||
        item.role.toLowerCase().includes(keyword)
      );
    });
  });

  const selectedBrowsePromptIndices = computed<number[]>(() => {
    return [...browseListState.selection.indices]
      .filter(index => selectedPreset.value?.prompts[index])
      .sort((lhs, rhs) => lhs - rhs);
  });

  const browseVisiblePromptIndices = computed<number[]>(() => filteredBrowsePromptItems.value.map(item => item.index));

  const presetSummaries = computed<PresetSummary[]>(() => {
    return presetNames.value.map(name => {
      const meta = ensureMeta(name);
      const preview = presetPreviewMap.value[name] ?? { prompt_count: 0, enabled_prompt_count: 0 };
      return {
        name,
        prompt_count: preview.prompt_count,
        enabled_prompt_count: preview.enabled_prompt_count,
        favorite: meta.favorite,
        tags: meta.tags,
        note: meta.note,
        is_loaded: name === loadedPresetName.value,
        is_selected: name === selectedPresetName.value,
      };
    });
  });

  const editPromptIndices = computed<number[]>(() => {
    if (!editDraft.value) {
      return [];
    }
    const keyword = editPromptQuery.value.trim().toLowerCase();
    if (!keyword) {
      return editDraft.value.prompts.map((_, index) => index);
    }
    return editDraft.value.prompts
      .map((prompt, index) => ({ prompt, index }))
      .filter(({ prompt }) => {
        return (
          prompt.name.toLowerCase().includes(keyword) ||
          prompt.id.toLowerCase().includes(keyword) ||
          prompt.role.toLowerCase().includes(keyword)
        );
      })
      .map(item => item.index);
  });

  function mutateState(mutator: (draft: typeof assistantState.value) => void): void {
    const next = mutateAssistantState(assistantState.value, mutator);
    assistantState.value = next;
    writeAssistantState(next);
  }

  function ensureMeta(name: string): typeof selectedMeta.value {
    if (!name) {
      return { favorite: false, tags: [], note: '', updated_at: 0 };
    }
    return (
      assistantState.value.meta_by_preset[name] ?? {
        favorite: false,
        tags: [],
        note: '',
        updated_at: 0,
      }
    );
  }

  function commitMeta(name: string, mutator: (meta: typeof selectedMeta.value) => void): void {
    if (!name) {
      return;
    }
    mutateState(draft => {
      const current = draft.meta_by_preset[name] ?? {
        favorite: false,
        tags: [],
        note: '',
        updated_at: 0,
      };
      const nextMeta = klona(current);
      mutator(nextMeta);
      nextMeta.updated_at = Date.now();
      draft.meta_by_preset[name] = nextMeta;
      draft.tag_catalog = [
        ...new Set(Object.values(draft.meta_by_preset).flatMap(meta => meta.tags).filter(Boolean)),
      ].sort((lhs, rhs) => lhs.localeCompare(rhs, 'zh-Hans-CN'));
    });
  }

  function updatePresetPreview(name: string, preset: Preset): void {
    presetPreviewMap.value = {
      ...presetPreviewMap.value,
      [name]: {
        prompt_count: preset.prompts.length,
        enabled_prompt_count: preset.prompts.filter(prompt => prompt.enabled).length,
      },
    };
  }

  function markPromptSaved(promptKey: string): void {
    quickPromptToggleState.last_saved_at_by_id[promptKey] = Date.now();
    window.setTimeout(() => {
      delete quickPromptToggleState.last_saved_at_by_id[promptKey];
    }, SAVE_FEEDBACK_MS);
  }

  function resetBrowseSettingsDraftFromPreset(preset: Preset): void {
    browseParamDraft.base_settings = cloneSettings(preset.settings);
    browseParamDraft.staged_settings = cloneSettings(preset.settings);
    browseParamDraft.dirty = false;
    browseParamDraft.applying = false;
  }

  function resetEditDraftFromPreset(preset: Preset): void {
    editDraft.value = clonePreset(preset);
    editDraftDirty.value = false;
    editSelectedPromptIndex.value = Math.max(
      0,
      Math.min(editSelectedPromptIndex.value, Math.max(0, editDraft.value.prompts.length - 1)),
    );
  }

  function clearBrowsePromptSelection(): void {
    browseListState.selection.indices.clear();
  }

  function setBrowsePromptQuery(query: string): void {
    browseListState.query = query;
  }

  function toggleBrowsePromptSelection(index: number, checked: boolean): void {
    if (!selectedPreset.value?.prompts[index]) {
      return;
    }
    if (checked) {
      browseListState.selection.indices.add(index);
      return;
    }
    browseListState.selection.indices.delete(index);
  }

  function setBrowsePromptSelectionForVisible(checked: boolean): void {
    if (checked) {
      for (const index of browseVisiblePromptIndices.value) {
        browseListState.selection.indices.add(index);
      }
      return;
    }
    for (const index of browseVisiblePromptIndices.value) {
      browseListState.selection.indices.delete(index);
    }
  }

  async function refreshPresetNames(): Promise<void> {
    const names = [...getPresetNames()].sort((lhs, rhs) => lhs.localeCompare(rhs, 'zh-Hans-CN'));
    loadedPresetName.value = getLoadedPresetName();
    presetNames.value = names;
    const fallbackPrompts = getFallbackPromptsFromHost();

    const nextPreviews: Record<string, PresetPreviewInfo> = {};
    for (const name of names) {
      try {
        const preset = normalizePresetForAssistant(getPreset(name), fallbackPrompts);
        nextPreviews[name] = {
          prompt_count: preset.prompts.length,
          enabled_prompt_count: preset.prompts.filter(prompt => prompt.enabled).length,
        };
      } catch {
        nextPreviews[name] = { prompt_count: 0, enabled_prompt_count: 0 };
      }
    }
    presetPreviewMap.value = nextPreviews;

    mutateState(draft => {
      for (const key of Object.keys(draft.meta_by_preset)) {
        if (!names.includes(key)) {
          delete draft.meta_by_preset[key];
        }
      }
      draft.tag_catalog = [
        ...new Set(Object.values(draft.meta_by_preset).flatMap(meta => meta.tags).filter(Boolean)),
      ].sort((lhs, rhs) => lhs.localeCompare(rhs, 'zh-Hans-CN'));
    });
  }

  async function loadPresetForBrowse(name: string): Promise<boolean> {
    if (!name) {
      selectedPresetName.value = '';
      selectedPreset.value = null;
      clearBrowsePromptSelection();
      return false;
    }
    loadingPreset.value = true;
    try {
      const fallbackPrompts = getFallbackPromptsFromHost();
      const preset = normalizePresetForAssistant(getPreset(name), fallbackPrompts);
      selectedPresetName.value = name;
      selectedPreset.value = clonePreset(preset);
      resetBrowseSettingsDraftFromPreset(preset);
      resetEditDraftFromPreset(preset);
      clearBrowsePromptSelection();
      browseListState.query = '';
      mutateState(draft => {
        draft.ui.last_selected_preset = name;
      });
      return true;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toastr.error(`加载预设失败: ${message}`, 'Preset Assistant');
      return false;
    } finally {
      loadingPreset.value = false;
    }
  }

  function queuePendingAction(action: PendingAction, reason: string): void {
    pendingAction.value = action;
    unsavedDialogReason.value = reason;
    unsavedDialogVisible.value = true;
  }

  async function flushBrowseAutoSaveQueue(): Promise<void> {
    await browseAutoSaveChain;
  }

  async function selectPreset(name: string): Promise<void> {
    if (!name || name === selectedPresetName.value) {
      return;
    }
    if (hasUnsavedChanges.value) {
      queuePendingAction({ type: 'select', target_name: name }, '切换预设前有未保存改动');
      return;
    }
    await flushBrowseAutoSaveQueue();
    await loadPresetForBrowse(name);
  }

  async function refreshStickyConnectionSnapshot(): Promise<void> {
    if (apiBindingMode.value !== 'sticky_connection') {
      return;
    }
    const snapshot = await captureCurrentConnectionSnapshot();
    mutateState(draft => {
      draft.sticky_connection_snapshot = snapshot;
    });
  }

  async function switchPresetWithConnectionPolicy(targetName = selectedPresetName.value): Promise<boolean> {
    if (!targetName) {
      toastr.warning('请先选择一个预设', 'Preset Assistant');
      return false;
    }
    if (hasUnsavedChanges.value) {
      queuePendingAction({ type: 'switch', target_name: targetName }, '切换生效预设前有未保存改动');
      return false;
    }
    await flushBrowseAutoSaveQueue();
    return await performSwitchPreset(targetName);
  }

  async function performSwitchPreset(targetName: string): Promise<boolean> {
    try {
      let stickySnapshot = assistantState.value.sticky_connection_snapshot;
      if (apiBindingMode.value === 'sticky_connection') {
        stickySnapshot = stickySnapshot ?? (await captureCurrentConnectionSnapshot());
        mutateState(draft => {
          draft.sticky_connection_snapshot = stickySnapshot;
        });
      }

      const switched = loadPreset(targetName);
      if (!switched) {
        toastr.error(`切换预设失败: ${targetName}`, 'Preset Assistant');
        return false;
      }

      if (apiBindingMode.value === 'sticky_connection' && stickySnapshot) {
        await applyConnectionSnapshot(stickySnapshot);
        toastr.success(`已切换预设并保持连接配置: ${targetName}`, 'Preset Assistant');
      } else {
        toastr.success(`已切换预设: ${targetName}`, 'Preset Assistant');
      }

      loadedPresetName.value = getLoadedPresetName();
      await loadPresetForBrowse(targetName);
      return true;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toastr.error(`切换预设失败: ${message}`, 'Preset Assistant');
      return false;
    }
  }

  async function persistPresetByName(name: string, nextPreset: Preset, render: ReplacePresetRender): Promise<void> {
    await replacePreset(name, nextPreset, { render });
    if (name === loadedPresetName.value) {
      await replacePreset('in_use', clonePreset(nextPreset), { render: 'debounced' });
    }
  }

  async function enqueueBrowseAutoSave(
    task: AutoSaveTask,
    saver: () => Promise<void>,
    onError: (error: unknown) => Promise<void> | void,
  ): Promise<void> {
    const queued = browseAutoSaveChain.then(async () => {
      browseAutoSaveRunning += 1;
      browseListState.saving = true;
      try {
        await saver();
        browseListState.last_saved_at = Date.now();
      } catch (error) {
        console.warn('[PresetAssistant] browse auto save failed:', task, error);
        await onError(error);
      } finally {
        browseAutoSaveRunning = Math.max(0, browseAutoSaveRunning - 1);
        browseListState.saving = browseAutoSaveRunning > 0;
      }
    });
    browseAutoSaveChain = queued.then(
      () => undefined,
      () => undefined,
    );
    return queued;
  }

  async function rollbackSelectedPresetFromHost(targetName: string): Promise<void> {
    if (selectedPresetName.value !== targetName) {
      return;
    }
    try {
      const fallbackPrompts = getFallbackPromptsFromHost();
      const hostPreset = normalizePresetForAssistant(getPreset(targetName), fallbackPrompts);
      selectedPreset.value = clonePreset(hostPreset);
      updatePresetPreview(targetName, hostPreset);
      clearBrowsePromptSelection();
      if (!editDraftDirty.value) {
        resetEditDraftFromPreset(hostPreset);
      }
      if (!browseParamDraft.dirty) {
        resetBrowseSettingsDraftFromPreset(hostPreset);
      }
    } catch (error) {
      console.warn('[PresetAssistant] rollback selected preset failed:', error);
    }
  }

  async function toggleBrowsePromptEnabledAndAutoSave(index: number, enabled: boolean): Promise<void> {
    if (!selectedPreset.value) {
      return;
    }
    const currentPrompt = selectedPreset.value.prompts[index];
    if (!currentPrompt || currentPrompt.enabled === enabled) {
      return;
    }

    const targetName = selectedPresetName.value;
    if (!targetName) {
      return;
    }

    const rollbackPreset = clonePreset(selectedPreset.value);
    const nextPreset = clonePreset(selectedPreset.value);
    nextPreset.prompts[index].enabled = enabled;
    const promptKey = buildPromptKey(nextPreset.prompts[index], index);

    selectedPreset.value = nextPreset;
    updatePresetPreview(targetName, nextPreset);
    quickPromptToggleState.saving_ids.add(promptKey);

    const task: AutoSaveTask = {
      id: `toggle-${browseAutoSaveCounter++}`,
      target_preset: targetName,
      description: `toggle:${index}`,
    };

    try {
      await enqueueBrowseAutoSave(
        task,
        async () => {
          await persistPresetByName(targetName, clonePreset(nextPreset), 'none');
          markPromptSaved(promptKey);
        },
        async error => {
          if (selectedPresetName.value === targetName) {
            selectedPreset.value = rollbackPreset;
            updatePresetPreview(targetName, rollbackPreset);
          }
          await rollbackSelectedPresetFromHost(targetName);
          const message = error instanceof Error ? error.message : String(error);
          toastr.error(`提示词开关保存失败: ${message}`, 'Preset Assistant');
        },
      );
    } finally {
      quickPromptToggleState.saving_ids.delete(promptKey);
    }
  }

  async function reorderBrowsePromptAndAutoSave(fromIndex: number, toIndex: number): Promise<void> {
    if (!selectedPreset.value || fromIndex === toIndex) {
      return;
    }
    const prompts = selectedPreset.value.prompts;
    if (!prompts[fromIndex] || !prompts[toIndex]) {
      return;
    }
    const targetName = selectedPresetName.value;
    if (!targetName) {
      return;
    }

    const rollbackPreset = clonePreset(selectedPreset.value);
    const nextPreset = clonePreset(selectedPreset.value);
    const [moving] = nextPreset.prompts.splice(fromIndex, 1);
    nextPreset.prompts.splice(toIndex, 0, moving);

    selectedPreset.value = nextPreset;
    updatePresetPreview(targetName, nextPreset);
    clearBrowsePromptSelection();

    const task: AutoSaveTask = {
      id: `reorder-${browseAutoSaveCounter++}`,
      target_preset: targetName,
      description: `reorder:${fromIndex}->${toIndex}`,
    };

    await enqueueBrowseAutoSave(
      task,
      async () => {
        await persistPresetByName(targetName, clonePreset(nextPreset), 'none');
      },
      async error => {
        if (selectedPresetName.value === targetName) {
          selectedPreset.value = rollbackPreset;
          updatePresetPreview(targetName, rollbackPreset);
        }
        await rollbackSelectedPresetFromHost(targetName);
        const message = error instanceof Error ? error.message : String(error);
        toastr.error(`排序保存失败: ${message}`, 'Preset Assistant');
      },
    );
  }

  async function batchSetBrowsePromptEnabledAndAutoSave(indices: number[], enabled: boolean): Promise<void> {
    if (!selectedPreset.value || indices.length < 1) {
      return;
    }
    const targetName = selectedPresetName.value;
    if (!targetName) {
      return;
    }
    const uniqueIndices = [...new Set(indices)].filter(index => selectedPreset.value?.prompts[index]);
    if (uniqueIndices.length < 1) {
      return;
    }

    const rollbackPreset = clonePreset(selectedPreset.value);
    const nextPreset = clonePreset(selectedPreset.value);
    const affectedKeys: string[] = [];
    for (const index of uniqueIndices) {
      const prompt = nextPreset.prompts[index];
      prompt.enabled = enabled;
      affectedKeys.push(buildPromptKey(prompt, index));
    }

    for (const key of affectedKeys) {
      quickPromptToggleState.saving_ids.add(key);
    }
    selectedPreset.value = nextPreset;
    updatePresetPreview(targetName, nextPreset);
    clearBrowsePromptSelection();

    const task: AutoSaveTask = {
      id: `batch-${browseAutoSaveCounter++}`,
      target_preset: targetName,
      description: `${enabled ? 'enable' : 'disable'}:${uniqueIndices.join(',')}`,
    };

    try {
      await enqueueBrowseAutoSave(
        task,
        async () => {
          await persistPresetByName(targetName, clonePreset(nextPreset), 'none');
          for (const key of affectedKeys) {
            markPromptSaved(key);
          }
        },
        async error => {
          if (selectedPresetName.value === targetName) {
            selectedPreset.value = rollbackPreset;
            updatePresetPreview(targetName, rollbackPreset);
          }
          await rollbackSelectedPresetFromHost(targetName);
          const message = error instanceof Error ? error.message : String(error);
          toastr.error(`批量操作保存失败: ${message}`, 'Preset Assistant');
        },
      );
    } finally {
      for (const key of affectedKeys) {
        quickPromptToggleState.saving_ids.delete(key);
      }
    }
  }

  function setBrowseStagedSetting(
    key: keyof Preset['settings'],
    value: Preset['settings'][keyof Preset['settings']],
  ): void {
    browseParamDraft.staged_settings = {
      ...browseParamDraft.staged_settings,
      [key]: value,
    };
    browseParamDraft.dirty = !_.isEqual(browseParamDraft.base_settings, browseParamDraft.staged_settings);
  }

  async function applyBrowseSettingsToPreset(): Promise<boolean> {
    if (!selectedPreset.value || !selectedPresetName.value || !browseParamDraft.dirty || browseParamDraft.applying) {
      return true;
    }
    browseParamDraft.applying = true;
    try {
      await flushBrowseAutoSaveQueue();
      const nextPreset = clonePreset(selectedPreset.value);
      nextPreset.settings = cloneSettings(browseParamDraft.staged_settings);
      await persistPresetByName(selectedPresetName.value, nextPreset, 'none');
      selectedPreset.value = nextPreset;
      browseParamDraft.base_settings = cloneSettings(nextPreset.settings);
      browseParamDraft.staged_settings = cloneSettings(nextPreset.settings);
      browseParamDraft.dirty = false;
      if (!editDraftDirty.value) {
        resetEditDraftFromPreset(nextPreset);
      }
      toastr.success('参数已应用到当前预设', 'Preset Assistant');
      return true;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toastr.error(`应用参数失败: ${message}`, 'Preset Assistant');
      return false;
    } finally {
      browseParamDraft.applying = false;
    }
  }

  function resetBrowseSettingsDraft(): void {
    browseParamDraft.staged_settings = cloneSettings(browseParamDraft.base_settings);
    browseParamDraft.dirty = false;
  }

  function setMetaFavorite(name: string, favorite: boolean): void {
    commitMeta(name, meta => {
      meta.favorite = favorite;
    });
  }

  function setMetaTags(name: string, rawTags: string): void {
    commitMeta(name, meta => {
      meta.tags = normalizeTags(rawTags);
    });
  }

  function setMetaNote(name: string, note: string): void {
    commitMeta(name, meta => {
      meta.note = note;
    });
  }

  function setUiMode(next: UiMode): void {
    uiMode.value = next;
  }

  function setEditApplyMode(mode: EditApplyMode): void {
    editApplyMode.value = mode;
  }

  function setEditPromptQuery(query: string): void {
    editPromptQuery.value = query;
  }

  function updateEditDraft(nextPreset: Preset): void {
    editDraft.value = clonePreset(nextPreset);
    editDraftDirty.value = selectedPreset.value ? !_.isEqual(nextPreset, selectedPreset.value) : false;
    editSelectedPromptIndex.value = Math.min(
      editSelectedPromptIndex.value,
      Math.max(0, (editDraft.value.prompts.length || 1) - 1),
    );
    if (editDraftDirty.value && editApplyMode.value === 'live') {
      scheduleEditLiveApply();
    }
  }

  function appendPromptToEditDraft(): void {
    if (!editDraft.value) {
      return;
    }
    const next = clonePreset(editDraft.value);
    next.prompts.push(createDefaultPrompt());
    updateEditDraft(next);
    editSelectedPromptIndex.value = next.prompts.length - 1;
  }

  function removePromptFromEditDraft(index: number): void {
    if (!editDraft.value || !editDraft.value.prompts[index]) {
      return;
    }
    const next = clonePreset(editDraft.value);
    next.prompts.splice(index, 1);
    updateEditDraft(next);
    editSelectedPromptIndex.value = Math.max(0, Math.min(editSelectedPromptIndex.value, next.prompts.length - 1));
  }

  function movePromptInEditDraft(index: number, direction: -1 | 1): void {
    if (!editDraft.value) {
      return;
    }
    const target = index + direction;
    if (target < 0 || target >= editDraft.value.prompts.length) {
      return;
    }
    const next = clonePreset(editDraft.value);
    const [current] = next.prompts.splice(index, 1);
    next.prompts.splice(target, 0, current);
    updateEditDraft(next);
    editSelectedPromptIndex.value = target;
  }

  function scheduleEditLiveApply(): void {
    if (editLiveApplyTimer !== null) {
      window.clearTimeout(editLiveApplyTimer);
    }
    editLiveApplyTimer = window.setTimeout(() => {
      editLiveApplyTimer = null;
      void applyEditDraftToInUse();
    }, EDIT_LIVE_APPLY_DELAY_MS);
  }

  async function applyEditDraftToInUse(): Promise<void> {
    if (!editDraft.value || !selectedPresetName.value) {
      return;
    }
    if (selectedPresetName.value !== loadedPresetName.value) {
      return;
    }
    try {
      await replacePreset('in_use', clonePreset(editDraft.value), { render: 'debounced' });
    } catch (error) {
      console.warn('[PresetAssistant] live apply failed:', error);
    }
  }

  async function saveEditDraftToPreset(): Promise<boolean> {
    if (!editDraft.value || !selectedPresetName.value || !editDraftDirty.value || editSaving.value) {
      return true;
    }
    editSaving.value = true;
    try {
      await flushBrowseAutoSaveQueue();
      await persistPresetByName(selectedPresetName.value, clonePreset(editDraft.value), 'none');
      selectedPreset.value = clonePreset(editDraft.value);
      editDraftDirty.value = false;
      updatePresetPreview(selectedPresetName.value, selectedPreset.value);
      resetBrowseSettingsDraftFromPreset(selectedPreset.value);
      toastr.success('编辑内容已保存', 'Preset Assistant');
      return true;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toastr.error(`保存编辑失败: ${message}`, 'Preset Assistant');
      return false;
    } finally {
      editSaving.value = false;
    }
  }

  function discardEditDraft(): void {
    if (!selectedPreset.value) {
      return;
    }
    resetEditDraftFromPreset(selectedPreset.value);
  }

  async function saveAllPendingChanges(): Promise<boolean> {
    await flushBrowseAutoSaveQueue();
    if (browseParamDraft.dirty) {
      const ok = await applyBrowseSettingsToPreset();
      if (!ok) {
        return false;
      }
    }
    if (editDraftDirty.value) {
      const ok = await saveEditDraftToPreset();
      if (!ok) {
        return false;
      }
    }
    return true;
  }

  function discardAllPendingChanges(): void {
    resetBrowseSettingsDraft();
    discardEditDraft();
  }

  async function resolveUnsavedDecision(decision: UnsavedDecision): Promise<void> {
    if (decision === 'cancel') {
      unsavedDialogVisible.value = false;
      pendingAction.value = null;
      return;
    }

    if (decision === 'save') {
      const saved = await saveAllPendingChanges();
      if (!saved) {
        return;
      }
    } else {
      discardAllPendingChanges();
    }

    const action = pendingAction.value;
    pendingAction.value = null;
    unsavedDialogVisible.value = false;
    await flushBrowseAutoSaveQueue();

    if (!action) {
      return;
    }
    if (action.type === 'select') {
      await loadPresetForBrowse(action.target_name);
      return;
    }
    if (action.type === 'switch') {
      await performSwitchPreset(action.target_name);
    }
  }

  async function refreshFromHost(): Promise<void> {
    const current = selectedPresetName.value;
    await refreshPresetNames();
    if (hasUnsavedChanges.value || browseListState.saving) {
      return;
    }
    if (!current) {
      return;
    }
    if (!presetNames.value.includes(current)) {
      const fallback = presetNames.value[0] ?? '';
      if (fallback) {
        await loadPresetForBrowse(fallback);
      } else {
        selectedPresetName.value = '';
        selectedPreset.value = null;
      }
      return;
    }
    await loadPresetForBrowse(current);
  }

  function bindTavernEvents(): void {
    if (subscriptions.value.length) {
      return;
    }
    subscriptions.value.push(
      eventOn(tavern_events.PRESET_CHANGED, () => {
        loadedPresetName.value = getLoadedPresetName();
        void refreshFromHost();
      }),
    );
    subscriptions.value.push(
      eventOn(tavern_events.PRESET_DELETED, () => {
        loadedPresetName.value = getLoadedPresetName();
        void refreshFromHost();
      }),
    );
    subscriptions.value.push(
      eventOn(tavern_events.PRESET_RENAMED, () => {
        loadedPresetName.value = getLoadedPresetName();
        void refreshFromHost();
      }),
    );
    subscriptions.value.push(
      eventOn(tavern_events.MAIN_API_CHANGED, () => {
        void refreshStickyConnectionSnapshot();
      }),
    );
    subscriptions.value.push(
      eventOn(tavern_events.CHATCOMPLETION_MODEL_CHANGED, () => {
        void refreshStickyConnectionSnapshot();
      }),
    );
    subscriptions.value.push(
      eventOn(tavern_events.CONNECTION_PROFILE_LOADED, () => {
        void refreshStickyConnectionSnapshot();
      }),
    );
    subscriptions.value.push(
      eventOn(tavern_events.CONNECTION_PROFILE_UPDATED, () => {
        void refreshStickyConnectionSnapshot();
      }),
    );
  }

  function teardown(): void {
    for (const subscription of subscriptions.value) {
      subscription.stop();
    }
    subscriptions.value = [];
    if (editLiveApplyTimer !== null) {
      window.clearTimeout(editLiveApplyTimer);
      editLiveApplyTimer = null;
    }
    initialized.value = false;
  }

  async function initialize(): Promise<void> {
    if (initialized.value) {
      return;
    }
    loadedPresetName.value = getLoadedPresetName();
    await refreshPresetNames();
    const fallback =
      (assistantState.value.ui.last_selected_preset &&
        presetNames.value.includes(assistantState.value.ui.last_selected_preset) &&
        assistantState.value.ui.last_selected_preset) ||
      (loadedPresetName.value && presetNames.value.includes(loadedPresetName.value) && loadedPresetName.value) ||
      presetNames.value[0] ||
      '';
    if (fallback) {
      await loadPresetForBrowse(fallback);
    }
    if (apiBindingMode.value === 'sticky_connection') {
      await refreshStickyConnectionSnapshot();
    }
    bindTavernEvents();
    initialized.value = true;
  }

  return {
    assistantState,
    presetNames,
    presetSummaries,
    selectedPresetName,
    selectedPreset,
    loadedPresetName,
    loadingPreset,
    uiMode,
    apiBindingMode,
    editApplyMode,
    browseParamPanelOpen,
    browseParamExpandedGroup,
    quickPromptItems,
    filteredBrowsePromptItems,
    browseVisiblePromptIndices,
    selectedBrowsePromptIndices,
    browseListState,
    browseParamDraft,
    selectedMeta,
    hasUnsavedChanges,
    unsavedDialogVisible,
    unsavedDialogReason,
    pendingAction,
    editDraft,
    editDraftDirty,
    editSelectedPromptIndex,
    editPromptQuery,
    editPromptIndices,
    editSaving,
    initialize,
    teardown,
    refreshFromHost,
    selectPreset,
    switchPresetWithConnectionPolicy,
    resolveUnsavedDecision,
    setBrowsePromptQuery,
    toggleBrowsePromptSelection,
    setBrowsePromptSelectionForVisible,
    clearBrowsePromptSelection,
    toggleBrowsePromptEnabledAndAutoSave,
    reorderBrowsePromptAndAutoSave,
    batchSetBrowsePromptEnabledAndAutoSave,
    setBrowseStagedSetting,
    applyBrowseSettingsToPreset,
    resetBrowseSettingsDraft,
    setMetaFavorite,
    setMetaTags,
    setMetaNote,
    setUiMode,
    setEditApplyMode,
    setEditPromptQuery,
    updateEditDraft,
    appendPromptToEditDraft,
    removePromptFromEditDraft,
    movePromptInEditDraft,
    saveEditDraftToPreset,
    discardEditDraft,
    saveAllPendingChanges,
    discardAllPendingChanges,
  };
});
