anel-head\">\n      <div class=\"title-wrap\">\n        <h3>Prompt 列表</h3>\n        <p>浏览态支持搜索、开关、排序、批量，修改自动保存</p>\n      </div>\n      <div class=\"stats\">\n        <span>{{ items.length }} 条</span>\n        <span v-if=\"lastSavedAt > 0\" class=\"saved-at\">已保存</span>\n      </div>\n    </header>\n\n    <div class=\"toolbar\">\n      <label class=\"search\">\n        <input\n          class=\"input\"\n          type=\"text\"\n          :value=\"query\"\n          placeholder=\"搜索 name / id / role\"\n          @input=\"emit('update-query', ($event.target as HTMLInputElement).value)\"\n        />\n      </label>\n      <label class=\"select-all\">\n        <input\n          type=\"checkbox\"\n          :checked=\"allVisibleSelected\"\n          :disabled=\"disabled || items.length < 1\"\n          @change=\"emit('select-visible', ($event.target as HTMLInputElement).checked)\"\n        />\n        <span>全选可见</span>\n      </label>\n      <button\n        class=\"btn mini\"\n        type=\"button\"\n        :disabled=\"disabled || selectedCount < 1 || saving\"\n        @click=\"emitBatch(true)\"\n      >\n        批量启用\n      </button>\n      <button\n        class=\"btn mini\"\n        type=\"button\"\n        :disabled=\"disabled || selectedCount < 1 || saving\"\n        @click=\"emitBatch(false)\"\n      >\n        批量禁用\n      </button>\n      <button\n        class=\"btn mini ghost\"\n        type=\"button\"\n        :disabled=\"disabled || selectedCount < 1\"\n        @click=\"emit('clear-selection')\"\n      >\n        清空选择\n      </button>\n    </div>\n\n    <div class=\"list\">\n      <article\n        v-for=\"item in items\"\n        :key=\"item.key\"\n        class=\"row\"\n        :data-kind=\"item.kind\"\n        draggable=\"true\"\n        @dragstart=\"onDragStart(item.index)\"\n        @dragover.prevent\n        @drop=\"onDrop(item.index)\"\n        @dragend=\"draggingIndex = null\"\n      >\n        <div class=\"row-left\">\n          <label class=\"pick\">\n            <input\n              type=\"checkbox\"\n              :checked=\"item.selected\"\n              :disabled=\"disabled || saving\"\n              @change=\"emit('select', item.index, ($event.target as HTMLInputElement).checked)\"\n            />\n          </label>\n          <div class=\"meta\">\n            <strong>{{ item.name || item.id }}</strong>\n            <small>{{ item.id }} · {{ item.role }}</small>\n          </div>\n        </div>\n\n        <div class=\"row-right\">\n          <span v-if=\"item.is_saving || saving\" class=\"state saving\">保存中</span>\n          <span v-else-if=\"item.is_recently_saved\" class=\"state saved\">已保存</span>\n          <div class=\"sort-buttons\">\n            <button class=\"sort-btn\" type=\"button\" :disabled=\"disabled || saving\" @click=\"emitMove(item.index, -1)\">\n              ↑\n            </button>\n            <button class=\"sort-btn\" type=\"button\" :disabled=\"disabled || saving\" @click=\"emitMove(item.index, 1)\">\n              ↓\n            </button>\n          </div>\n          <label class=\"switch\">\n            <input\n              type=\"checkbox\"\n              :checked=\"item.enabled\"\n              :disabled=\"disabled || item.is_saving || saving\"\n              @change=\"emit('toggle', item.index, ($event.target as HTMLInputElement).checked)\"\n            />\n            <span class=\"slider\"></span>\n          </label>\n        </div>\n      </article>\n      <div v-if=\"items.length < 1\" class=\"empty\">没有匹配的 Prompt</div>\n    </div>\n\n    <footer class=\"footer\">\n      <span>已选 {{ selectedCount }} / {{ visibleIndices.length }}</span>\n      <span v-if=\"saving\" class=\"saving\">自动保存队列处理中...</span>\n    </footer>\n  </section>\n</template>\n\n<script setup lang=\"ts\">\nimport { ref } from 'vue';\n\nimport type { PromptQuickItem } from '../types';\n\nconst props = defineProps<{\n  items: PromptQuickItem[];\n  query: string;\n  selectedCount: number;\n  selectedIndices: number[];\n  visibleIndices: number[];\n  allVisibleSelected: boolean;\n  saving: boolean;\n  lastSavedAt: number;\n  disabled?: boolean;\n}>();\n\nconst emit = defineEmits<{\n  'update-query': [query: string];\n  toggle: [index: number, enabled: boolean];\n  select: [index: number, checked: boolean];\n  'select-visible': [checked: boolean];\n  'clear-selection': [];\n  reorder: [fromIndex: number, toIndex: number];\n  'batch-set-enabled': [indices: number[], enabled: boolean];\n}>();\n\nconst draggingIndex = ref<number | null>(null);\n\nfunction emitMove(index: number, direction: -1 | 1): void {\n  emit('reorder', index, index + direction);\n}\n\nfunction onDragStart(index: number): void {\n  draggingIndex.value = index;\n}\n\nfunction onDrop(targetIndex: number): void {\n  if (draggingIndex.value === null || draggingIndex.value === targetIndex) {\n    draggingIndex.value = null;\n    return;\n  }\n  emit('reorder', draggingIndex.value, targetIndex);\n  draggingIndex.value = null;\n}\n\nfunction emitBatch(enabled: boolean): void {\n  emit('batch-set-enabled', props.selectedIndices, enabled);\n}\n</script>\n\n<style scoped>\n.prompt-panel {\n  border: 1px solid var(--pa-border-strong);\n  border-radius: 14px;\n  background: linear-gradient(160deg, rgba(8, 15, 30, 0.94), rgba(6, 11, 23, 0.94));\n  display: grid;\n  grid-template-rows: auto auto auto auto;\n  min-height: 0;\n}\n\n.panel-head {\n  display: flex;\n  justify-content: space-between;\n  gap: 12px;\n  align-items: start;\n  padding: 12px 14px;\n  border-bottom: 1px solid var(--pa-border);\n}\n\n.title-wrap h3 {\n  margin: 0;\n  font-size: 15px;\n  color: var(--pa-text-1);\n}\n\n.title-wrap p {\n  margin: 4px 0 0;\n  color: var(--pa-text-3);\n  font-size: 12px;\n}\n\n.stats {\n  display: grid;\n  gap: 4px;\n  justify-items: end;\n  color: var(--pa-text-2);\n  font-size: 12px;\n}\n\n.saved-at {\n  color: var(--pa-success);\n}\n\n.toolbar {\n  display: grid;\n  grid-template-columns: minmax(220px, 1fr) auto auto auto auto;\n  gap: 8px;\n  padding: 10px 14px;\n  border-bottom: 1px solid var(--pa-border);\n}\n\n.search {\n  min-width: 0;\n}\n\n.input {\n  width: 100%;\n  min-height: 34px;\n  border: 1px solid var(--pa-border-strong);\n  border-radius: 9px;\n  background: rgba(12, 22, 42, 0.9);\n  color: var(--pa-text-1);\n  padding: 0 10px;\n}\n\n.select-all {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  color: var(--pa-text-2);\n  font-size: 12px;\n}\n\n.btn {\n  border: 1px solid var(--pa-border-strong);\n  border-radius: 8px;\n  background: rgba(34, 54, 89, 0.7);\n  color: var(--pa-text-1);\n  cursor: pointer;\n}\n\n.btn.mini {\n  min-height: 34px;\n  padding: 0 10px;\n  font-size: 12px;\n}\n\n.btn.ghost {\n  background: rgba(10, 18, 34, 0.7);\n}\n\n.btn:disabled {\n  opacity: 0.45;\n  cursor: not-allowed;\n}\n\n.list {\n  overflow: visible;\n  min-height: 0;\n}\n\n.row {\n  display: flex;\n  justify-content: space-between;\n  gap: 10px;\n  padding: 9px 14px;\n  border-bottom: 1px solid rgba(64, 89, 128, 0.35);\n}\n\n.row[data-kind='system'] {\n  background: rgba(42, 93, 189, 0.12);\n}\n\n.row[data-kind='placeholder'] {\n  background: rgba(13, 148, 136, 0.12);\n}\n\n.row-left {\n  min-width: 0;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.pick {\n  display: inline-flex;\n}\n\n.meta {\n  display: grid;\n  gap: 2px;\n}\n\n.meta strong {\n  color: var(--pa-text-1);\n  font-size: 13px;\n  white-space: nowrap;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  max-width: 46vw;\n}\n\n.meta small {\n  color: var(--pa-text-3);\n  font-size: 11px;\n}\n\n.row-right {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.state {\n  font-size: 11px;\n  min-width: 40px;\n  text-align: right;\n}\n\n.state.saving {\n  color: var(--pa-warning);\n}\n\n.state.saved {\n  color: var(--pa-success);\n}\n\n.sort-buttons {\n  display: inline-flex;\n  gap: 4px;\n}\n\n.sort-btn {\n  width: 24px;\n  height: 24px;\n  border: 1px solid var(--pa-border-strong);\n  border-radius: 6px;\n  background: rgba(11, 20, 37, 0.8);\n  color: var(--pa-text-2);\n  cursor: pointer;\n  line-height: 1;\n}\n\n.sort-btn:disabled {\n  opacity: 0.4;\n  cursor: not-allowed;\n}\n\n.switch {\n  position: relative;\n  width: 44px;\n  height: 24px;\n  display: inline-block;\n}\n\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n.slider {\n  position: absolute;\n  inset: 0;\n  border-radius: 999px;\n  background: rgba(88, 108, 140, 0.6);\n  transition: 0.18s;\n}\n\n.slider::before {\n  content: '';\n  position: absolute;\n  width: 18px;\n  height: 18px;\n  left: 3px;\n  top: 3px;\n  border-radius: 50%;\n  background: #f8fbff;\n  transition: 0.18s;\n}\n\ninput:checked + .slider {\n  background: #2f6fdf;\n}\n\ninput:checked + .slider::before {\n  transform: translateX(20px);\n}\n\n.empty {\n  padding: 18px;\n  color: var(--pa-text-3);\n  text-align: center;\n}\n\n.footer {\n  border-top: 1px solid var(--pa-border);\n  min-height: 34px;\n  padding: 0 14px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  color: var(--pa-text-3);\n  font-size: 12px;\n}\n\n.footer .saving {\n  color: var(--pa-warning);\n}\n\n@media (max-width: 1024px) {\n  .toolbar {\n    grid-template-columns: 1fr 1fr;\n  }\n\n  .meta strong {\n    max-width: 36vw;\n  }\n}\n</style>\n"],"sourceRoot":""}]);
